import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Installation Planning","description":"","frontmatter":{},"headers":[],"relativePath":"admin/installation.md","filePath":"admin/installation.md","lastUpdated":1783543014000}'),o={name:"admin/installation.md"};function s(n,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="installation-planning" tabindex="-1">Installation Planning <a class="header-anchor" href="#installation-planning" aria-label="Permalink to &quot;Installation Planning&quot;">​</a></h1><p>This page lists planning checks for installing prokube. It is not a substitute for release-specific installation instructions or deployment automation.</p><h2 id="kubernetes-cluster" tabindex="-1">Kubernetes Cluster <a class="header-anchor" href="#kubernetes-cluster" aria-label="Permalink to &quot;Kubernetes Cluster&quot;">​</a></h2><p>prokube runs on Kubernetes. The exact supported Kubernetes versions, ingress stack, storage classes, and cloud-provider integrations are release-specific.</p><p>Before installation, confirm:</p><ul><li>Kubernetes version and distribution are supported by the target prokube release;</li><li>nodes have enough CPU, memory, storage, and optional GPU capacity for the selected product tracks;</li><li>the cluster has a default StorageClass and any additional classes needed for object storage, notebooks, databases, and model-serving workloads;</li><li>a CSI driver and snapshot support exist if backup workflows depend on volume snapshots;</li><li>administrators have <code>kubectl</code> and cluster-admin access for bootstrap and recovery.</li></ul><p>MicroK8s can be suitable for very small self-managed deployments. Production and multi-user deployments need capacity, availability, backup, storage, and operational controls sized for the expected workloads.</p><h2 id="dns-and-tls" tabindex="-1">DNS and TLS <a class="header-anchor" href="#dns-and-tls" aria-label="Permalink to &quot;DNS and TLS&quot;">​</a></h2><p>Plan stable DNS and trusted TLS before onboarding users.</p><p>At minimum, decide:</p><ul><li>the public prokube domain;</li><li>whether applications use path-prefix routing on the main domain or dedicated subdomains;</li><li>certificate issuer and renewal process;</li><li>how private or self-signed certificate authorities are distributed to users, workloads, and platform components.</li></ul><p>Several platform services rely on browser redirects. Incorrect root URLs, missing TLS trust, or changed hostnames commonly break login and OIDC flows.</p><h2 id="networking-and-firewall" tabindex="-1">Networking and Firewall <a class="header-anchor" href="#networking-and-firewall" aria-label="Permalink to &quot;Networking and Firewall&quot;">​</a></h2><p>The cluster needs outbound access for image pulls, package downloads, identity-provider endpoints, object-storage targets, and webhook integrations used by the deployment. Inbound access should be restricted to the gateways and admin access paths that are intentionally exposed.</p><p>Do not publish broad Kubernetes control-plane or node ports unless the deployment architecture requires them. Use private networking, VPN, bastion hosts, or provider-native access controls for administrative access.</p><h2 id="identity-and-sso" tabindex="-1">Identity and SSO <a class="header-anchor" href="#identity-and-sso" aria-label="Permalink to &quot;Identity and SSO&quot;">​</a></h2><p>Decide whether prokube will use local Keycloak users, an external corporate identity provider, or both.</p><p>Before production rollout:</p><ul><li>configure external IdP integration if needed;</li><li>test login with a normal user and an administrator;</li><li>define default groups and workspace access process;</li><li>document break-glass administrator access;</li><li>define client-secret rotation ownership.</li></ul><p>See <a href="./identity_providers.html">Identity Providers</a> for external IdP guidance.</p><h2 id="registry-and-source-repositories" tabindex="-1">Registry and Source Repositories <a class="header-anchor" href="#registry-and-source-repositories" aria-label="Permalink to &quot;Registry and Source Repositories&quot;">​</a></h2><p>prokube workloads pull platform images, user images, pipeline component images, notebook images, and serving images. Plan:</p><ul><li>which container registries are allowed;</li><li>how global image pull secrets are managed;</li><li>how workspace-specific registry credentials are created;</li><li>which Git or GitOps repositories are authoritative for deployment configuration;</li><li>whether users can build and push images from Labs.</li></ul><p>See <a href="./operations_runbooks.html#workspace-defaults-and-image-pull-secrets">Workspace Defaults and Image Pull Secrets</a> and <a href="./../platform/kubernetes.html#registry-credentials">Registry Credentials</a>.</p><h2 id="storage-sizing" tabindex="-1">Storage Sizing <a class="header-anchor" href="#storage-sizing" aria-label="Permalink to &quot;Storage Sizing&quot;">​</a></h2><p>Object storage, notebook volumes, MLflow artifacts, pipeline artifacts, and model files can grow quickly. Size MinIO tenants, databases, and persistent-volume storage before onboarding users.</p><p>For production deployments, avoid accepting placeholder storage sizes from a demo installation. Define expected retention, dataset size, model size, pipeline concurrency, and backup requirements first.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./storage.html">Storage</a></li><li><a href="./backup_restore.html">Backup and Restore</a></li><li><a href="./identity_providers.html">Identity Providers</a></li><li><a href="./operations_runbooks.html">Operations Runbooks</a></li></ul>',29)])])}const m=a(o,[["render",s]]);export{h as __pageData,m as default};
